(window.webpackJsonp=window.webpackJsonp||[]).push([[23],{542:function(e,a,t){"use strict";t.r(a);var i=t(11),r=Object(i.a)({},(function(){var e=this,a=e.$createElement,t=e._self._c||a;return t("ContentSlotsDistributor",{attrs:{"slot-key":e.$parent.slotKey}},[t("h1",{attrs:{id:"invasive-management-of-acute-myocardial-infarction-complicated-by-cardiogenic-shock"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#invasive-management-of-acute-myocardial-infarction-complicated-by-cardiogenic-shock"}},[e._v("#")]),e._v(" Invasive Management of Acute Myocardial Infarction Complicated by Cardiogenic Shock")]),e._v(" "),t("p",[e._v("A Scientific Statement From the American Heart Association")]),e._v(" "),t("p",[e._v("Timothy D. Henry , Matthew I. Tomey , Jacqueline E. Tamis-Holland\nOriginally published 4 Mar 2021")]),e._v(" "),t("p",[e._v("https://doi.org/10.1161/CIR.0000000000000959Circulation")]),e._v(" "),t("h2",{attrs:{id:"abstract"}},[t("a",{staticClass:"header-anchor",attrs:{href:"#abstract"}},[e._v("#")]),e._v(" Abstract")]),e._v(" "),t("p",[e._v("Cardiogenic shock (CS) remains the most common cause of mortality in patients with acute myocardial infarction. The SHOCK trial (Should We Emergently Revascularize Occluded Coronaries for Cardiogenic Shock) demonstrated a survival benefit with early revascularization in patients with CS complicating acute myocardial infarction (AMICS) 20 years ago. After an initial improvement in mortality related to revascularization, mortality rates have plateaued. A recent Society of Coronary Angiography and Interventions classification scheme was developed to address the wide range of CS presentations. In addition, a recent scientific statement from the American Heart Association recommended the development of CS centers using standardized protocols for diagnosis and management of CS, including mechanical circulatory support devices (MCS). A number of CS programs have implemented various protocols for treating patients with AMICS, including the use of MCS, and have published promising results using such protocols. Despite this, practice patterns in the cardiac catheterization laboratory vary across health systems, and there are inconsistencies in the use or timing of MCS for AMICS. Furthermore, mortality benefit from MCS devices in AMICS has yet to be established in randomized clinical trials. In this article, we outline the best practices for the contemporary interventional management of AMICS, including coronary revascularization, the use of MCS, and special considerations such as the treatment of patients with AMICS with cardiac arrest.")]),e._v(" "),t("p",[e._v("Cardiogenic  shock  (CS)  represents  an  inability  of  the  heart  to  maintain  an  effective  cardiac  out-put commensurate to the metabolic demands of the  body  attributable  to  a  primary  underlying  cardiac  pathology.  Acute  myocardial  infarction  (AMI)  is  the  most  common  cause  of  CS.1  Although  the  incidence  of  ST-segment–elevation  myocardial  infarction  (STEMI)  is  decreasing,  the  incidence  of  CS  complicating  AMI  (AMICS) remains stable (7%–10%) if not increasing, es-pecially among the elderly.2 An array of acute or acute-on-chronic  insults  can  contribute  to  its  pathogenesis,  including exacerbations of ischemic heart disease, val-vular  disease,  cardiomyopathy,  pericardial  disease,  or  arrhythmia.  Regardless  of  cause,  CS  results  in  a  defi-ciency  of  end-organ  perfusion  that  is  often  character-ized  by  hypotension,  tachycardia,  peripheral  vasocon-striction,  pulmonary  and  systemic  venous  congestion,  decreased  urine  output,  altered  sensorium,  acute  liver  or kidney injury, and lactic acidosis.3–5 Although CS re-mains  a  clinical  diagnosis,  objective  definitions  have  been established by clinical trials,6,7 and a recent docu-ment has proposed a novel classification system based on clinical characteristics at presentation.")]),e._v(" "),t("p",[e._v("Mortality associated with AMICS remains high, with 30-day  mortality  approximating  40%  to  45%  in  con-temporary  randomized  trials.7,9  After  the  SHOCK  trial  (Should  We  Emergently  Revascularize  Occluded  Coro-naries  for  CS),6  which  demonstrated  survival  benefit  with early revascularization in AMICS at longer follow-up,  and  with  growth  in  availability  of  primary  percu-taneous coronary intervention (PCI), AMICS-associated mortality declined.10 From 2005 to 2013, this improve-ment appeared to plateau in an analysis of the National Cardiovascular Data Registry despite increasing rates of PCI.11 Mechanical circulatory support (MCS) devices are increasingly used in AMICS, but their effect on mortality has yet to be established in randomized clinical trials.4")]),e._v(" "),t("p",[e._v("The  AMIS  registry  (AMI  in  Switzerland)  of  83  Swiss  hospitals documented a decrease in AMI mortality from 8.7% to 7.3% from 1997 to 2017 (P<0.001 for trend)12and a decrease in development of CS in hospital from 7.8%  to  3.5%  over  the  same  time  period.  This  was  offset,  however,  by  an  increase  in  CS  at  presentation  from 2.5% to 4.6%. Overall, in-hospital mortality of all patients with AMICS decreased from 62.2% in 1997 to 36.3% in 2017 (P<0.001 for temporal trend; Figure 1), likely  related  to  the  growth  in  primary  PCI.  Of  note,  patients with AMICS who survive to hospital discharge continue to experience a higher rate of mortality after discharge. In a large series of patients ≥65 years of age surviving  to  hospital  discharge  in  the  ACTION  registry  (Acute Coronary Treatment and Intervention Outcomes Network), mortality was higher at 60 days (9.6% versus 5.5%) and at 1 year (22.4% versus 16.7%) in patients with  AMI  with  CS  compared  with  patients  with  AMI  without CS.")])])}),[],!1,null,null,null);a.default=r.exports}}]);